    public void ShouldGetMasterCorrectly(ModeValues mode, DigestSizes digestSize, string expectedMasterString, string keyString, bool psk, SPDMVersions version, string TH1String, string TH2String)
    {
        var hash = new HashFunction(mode, digestSize);
        var key = new BitString(keyString);
        var TH1 = new BitString(TH1String);
        var TH2 = new BitString(TH2String);

        var spdm = new Spdm(hash);
        var res = spdm.KeySchedule(key, psk, version, TH1, TH2);

        Assert.That(res.ExportMaster.ToHex().ToLower(), Is.EqualTo(expectedMasterString.ToLower()), res.ExportMaster.ToHex().ToLower());
    }
